from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject
    from collections import defaultdict
    triples_by_subject: dict[str, list[Triple]] = defaultdict(list)
    for triple in triples:
        triples_by_subject[triple.subject].append(triple)

    # Identify the main subject (prefer monument-like subjects)
    main_subject = None
    for s in triples_by_subject.keys():
        if any(term in s.lower() for term in ["monument", "memorial", "plack", "battlefield", "park"]):
            main_subject = s
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Build the main sentence for the main subject
    main_triples = triples_by_subject.get(main_subject, [])
    main_clauses: list[str] = []
    related_entities: list[tuple[str, str, str]] = []  # (entity, predicate, object)

    for triple in main_triples:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        # Map predicates to natural‑language fragments
        if p == "category":
            main_clauses.append(f"is a {o}")
        elif p == "country":
            main_clauses.append(f"is in {o}")
            related_entities.append((o, None, None))
        elif p == "location":
            main_clauses.append(f"is located in {o}")
            related_entities.append((o, None, None))
        elif p == "municipality":
            main_clauses.append(f"is in the municipality of {o}")
            related_entities.append((o, None, None))
        elif p == "state":
            main_clauses.append(f"in the state of {o}")
            related_entities.append((o, None, None))
        elif p == "district":
            main_clauses.append(f"is part of the district {o}")
            related_entities.append((o, None, None))
        elif p in ("established", "foundingDate"):
            # Format date more naturally
            if o and len(o) >= 10 and o[4] == '-' and o[7] == '-':
                try:
                    year, month, day = o[:4], o[5:7], o[8:10]
                    months = ["January", "February", "March", "April", "May", "June",
                              "July", "August", "September", "October", "November", "December"]
                    o = f"{months[int(month)-1]} {int(day)}, {year}"
                except:
                    pass
            main_clauses.append(f"was established on {o}")
        elif p in ("owner", "owningOrganisation"):
            main_clauses.append(f"is owned by {o}")
        elif p == "inaugurationDate":
            main_clauses.append(f"was inaugurated on {o}")
        elif p == "dedicatedTo":
            main_clauses.append(f"is dedicated to {o}")
        elif p == "designer":
            main_clauses.append(f"was designed by {o}")
        elif p == "material":
            main_clauses.append(f"is made of {o}")
        elif p == "nearestCity":
            main_clauses.append(f"is near {o}")
            related_entities.append((o, None, None))
        elif p == "nativeName":
            main_clauses.append(f'native name is "{o}"')
        elif p == "district":
            main_clauses.append(f"is in the district {o}")
            related_entities.append((o, None, None))
        else:
            # Fallback for any unexpected predicate
            main_clauses.append(f"{p.replace('_', ' ')} {o}")

    # Build related entity info
    related_info = []
    for entity, pred, obj in related_entities:
        if entity in triples_by_subject:
            entity_triples = triples_by_subject[entity]
            entity_clauses = []
            for et in entity_triples:
                ep = et.predicate
                eo = et.object.strip('"')
                if ep == "capital":
                    entity_clauses.append(f"capital is {eo}")
                elif ep == "largestCity":
                    entity_clauses.append(f"largest city is {eo}")
                elif ep == "currency":
                    entity_clauses.append(f"uses {eo}")
                elif ep == "language":
                    entity_clauses.append(f"language is {eo}")
                elif ep == "ethnicGroup":
                    entity_clauses.append(f"ethnic group includes {eo}")
                elif ep == "country":
                    entity_clauses.append(f"is in {eo}")
                elif ep == "state":
                    entity_clauses.append(f"in state {eo}")
                elif ep == "hasToItsNorth":
                    entity_clauses.append(f"has Cumberland County to its north")
                elif ep == "hasToItsSouthwest":
                    entity_clauses.append(f"has Frederick County to its southwest")
                elif ep == "hasToItsWest":
                    entity_clauses.append(f"has Franklin County to its west")
                elif ep == "hasToItsSoutheast":
                    entity_clauses.append(f"has Carroll County to its southeast")
                elif ep == "nearestCity":
                    entity_clauses.append(f"nearest city is {eo}")
                elif ep == "leader":
                    entity_clauses.append(f"leader is {eo}")
                elif ep == "leaderTitle":
                    entity_clauses.append(f"leader title is {eo}")
                elif ep == "legislature":
                    entity_clauses.append(f"legislature is {eo}")
                elif ep == "religion":
                    entity_clauses.append(f"religion is {eo}")

            if entity_clauses:
                related_info.append((entity, ", ".join(entity_clauses)))

    # Build final sentence
    if main_clauses:
        if len(main_clauses) == 1:
            main_text = f"{main_subject} {main_clauses[0]}."
        else:
            main_text = f"{main_subject} " + ", ".join(main_clauses) + "."

        # Add related entity info with relative clauses
        for entity, info in related_info:
            if main_text.endswith("."):
                main_text = main_text[:-1] + f", which is in {entity}, where {info}."
            else:
                main_text += f", and {entity} {info}."

        return main_text
    else:
        return f"{main_subject}."

